head.script:
/**
 * 팝업 클로즈시 화면 회색처리를 해제한다.
 * @param
 * @return
 */
scwin.onpageunload = function() {
	if (document.getElementById("_modal").style.display == "block") {
		document.getElementById("_modal").style.display = "none";
	}
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSPB1200000");
	scwin.searchDatas();
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	scwin.param = JSON.parse($p.getPopupParam());
	// 데이터 조회
	scwin.btnInqire_onclick();
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	if (scwin.param.planEsntlId) {
		var queryString = `?planEsntlId=${scwin.param.planEsntlId}`;
		queryString += `&cnstrcEsntlId=${scwin.param.cnstrcEsntlId}`;
	} else {
		var queryString = `?dsuseEsntlId=${scwin.param.dsuseEsntlId}`;
	}

	var option = {
		action : "zz/cmmn/retrieve-ectcc-prgs.do"
			+ queryString,
		method : "get",
		resData : dltEctccList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCallback = function(res) {
	spnTotalRow.setValue(dltEctccList.getRowCount());
};

/**
 * 그리드 더블클릭시 모달을 띄운다.
 * @param <Int> row, <Int> col, <String> colId
 */
scwin.grdEctccList_oncelldblclick = function(row, col, colId) {
	var apprId = grdEctccList.getCellData(row, "ectccId");
	if (apprId && apprId.trim()) {
		// comLib.alert($p, "문서가 열리는데 시간이 다소 소요될 수 있습니다.");
		var url = `${ecsLib.DOC_VIEWER_URL}?APPRID=${apprId}`;
		window.open(url, "전자문서", "toolbar=no,menubar=yes,location=no,directories=yes,status=yes,scrollbars=yes,resizable=yes,width=800,height=600,fullscreen=yes");
	} else {
		comLib.alert($p, "잘못된 문서입니다.");
	}
};

/**
 * 그리드 클릭시 모달을 띄운다.
 */
scwin.grdEctccList_oncellclick = function(row, col, colId) {
	if (colId == "ectccTit") {
		scwin.grdEctccList_oncelldblclick(row, col, colId);
	}
};
